sql:
SELECT patient_id, genetic_id
FROM genetic_markers
WHERE patient_id > 1 AND apoe4_1 = 1;

SELECT patient_id
FROM lifestyle_factors
WHERE any_bt_1 = 1;

external_knowledge:
- 'Initial therapy' refers to 'Treatment1'.;
- APOE4 gene status shows whether a patient has 2 copies of the APOE4 gene.;
- Baseline hippocampus volume refers to the initial measurement of hippocampus volume for the patients.;
- Sorting in descending order for gene status means that patients with 2 copies of the APOE4 gene will appear first in the list.

sql:
SELECT image_id, patient_id, fdg_bl AS highest_fdg_pet_uptake
FROM neuroimaging
WHERE fdg_bl = (SELECT MAX(fdg_bl) FROM neuroimaging);

SELECT image_id, ventricles_bl, hippocampus_bl, wholebrain_bl, entorhinal_bl, fusiform_bl, midtemp_bl, icv_bl, fdg_bl, av45_bl, image_date, image_location, image_conducted_by, image_quality, notes
FROM neuroimaging
WHERE wholebrain_bl > (SELECT AVG(wholebrain_bl) FROM neuroimaging);

external_knowledge:
- Genetic tests refer to the unique genetic_id records;
- Neuroimaging scans refer to unique image_id records;
- Treatment outcomes refer to unique outcome_id records;
- Patients without any lifestyle assessments are those who have no records in the lifestyle_factors table.

sql:
SELECT AVG(ventricles_bl) AS Avg_Ventricles_Jan_2023
FROM neuroimaging
WHERE strftime('%Y-%m', image_date) = '2023-01';

SELECT patient_id, image_quality
FROM neuroimaging
WHERE ventricles_bl > (SELECT AVG(ventricles_bl) FROM neuroimaging);

SELECT patient_id
FROM lifestyle_factors
WHERE (calcium_0 = 1 OR any_bt_1 = 1) AND stress_levels = 'low';

SELECT *
FROM treatment_outcomes
WHERE treatment_type = 'Radiation Therapy' AND treatment_dosage = 'High';
